func (q *Queries) UpdateProductSpu(ctx context.Context, arg UpdateProductSpuParams) (CatalogProductSpu, error) {
	row := q.db.QueryRow(ctx, updateProductSpu,
		arg.Slug,
		arg.AccountID,
		arg.CategoryID,
		arg.BrandID,
		arg.NullFeaturedSkuID,
		arg.FeaturedSkuID,
		arg.Name,
		arg.Description,
		arg.IsActive,
		arg.Specifications,
		arg.DateCreated,
		arg.DateUpdated,
		arg.NullDateDeleted,
		arg.DateDeleted,
		arg.ID,
	)
	var i CatalogProductSpu
	err := row.Scan(
		&i.ID,
		&i.Slug,
		&i.AccountID,
		&i.CategoryID,
		&i.BrandID,
		&i.FeaturedSkuID,
		&i.Name,
		&i.Description,
		&i.IsActive,
		&i.Specifications,
		&i.DateCreated,
		&i.DateUpdated,
		&i.DateDeleted,
		&i.Number,
	)
	return i, err
}
